pRe=()=>"INTREDESNELHEID",uRe=()=>"PERIAPSIS",$Re=()=>"INCLINATIE",gRe=()=>"BAANINTREDE ∆V",mRe=()=>"TOTAAL ∆V",hRe=()=>"TLI/TMI ∆V",bRe=e=>`${e.value} km²/s²`,yRe=e=>`${e.value} km/s`,fRe=e=>`${e.value} kg`,vRe=e=>`${e.value} km`,kRe=e=>`${e.value}°`,CRe=()=>"Gereconstrueerde vluchtgegevens — waarden bij benadering.",SRe=()=>"Beperkte openbare gegevens — sommige waarden niet beschikbaar.",ERe=()=>"Vluchtgegevens nog niet onderzocht voor deze missie.",TRe=()=>"LANCERING",ARe=()=>"TLI/TMI-VERBRANDING",RRe=()=>"KOERSCORRECTIE",wRe=()=>"AANKOMST",NRe=()=>"EDL / BAANINTREDE",IRe=()=>"SCHEERVLUCHT",ORe=()=>"TERUGKEER NAAR AARDE",zRe=()=>"ANOMALIE",LRe=e=>`T+${e.day}d`,URe=()=>"src:",xRe=()=>"PRE-LANCERING",jRe=()=>"HEENREIS",DRe=()=>"TERUGREIS",BRe=()=>"AANGEKOMEN",MRe=()=>"3D",PRe=()=>"2D",qRe=()=>"VOERTUIG",VRe=()=>"VERTREK",GRe=()=>"AANKOMST",HRe=()=>"MET",FRe=()=>"HELIO ∆V",WRe=()=>"VANAF AARDE",ZRe=()=>"VANAF MARS",KRe=e=>`${e.value} l-min`,XRe=e=>`${e.value} M km`,YRe=e=>`${e.value} km/s`,JRe=()=>"∆V RESTEREND",QRe=()=>"∆V GEBRUIKT",ewe=()=>"ETA",awe=e=>`DAG ${e.day}`,nwe=e=>`DAG ${e.day}`,twe=()=>"SNELHEID",swe=()=>"Afspelen",owe=()=>"Pauze",iwe=()=>"Tijdlijn",rwe=()=>"Kon missie niet laden. ORRERY-1 vrije-terugkeer wordt standaard getoond.",_we=()=>"Missie",lwe=()=>"NAVIGATIE",cwe=()=>"Systemen",dwe=()=>"Vluchtparameters",pwe=()=>"C3",uwe=()=>"V∞",$we=()=>"TOTAAL ∆V",gwe=e=>`${e.value} km²/s²`,mwe=()=>"GERECONSTRUEERDE VLUCHTGEGEVENS — WAARDEN BIJ BENADERING",hwe=()=>"BEPERKTE OPENBARE GEGEVENS — SOMMIGE WAARDEN ONTBREKEN",bwe=()=>"VLUCHTGEGEVENS NOG NIET ONDERZOCHT",ywe=()=>"NEXT",fwe=e=>`T+${e.day}d`,vwe=e=>`T-${e.day}d`,kwe=()=>"CAPCOM-monitoring",Cwe=()=>"MISSIE-EVENEMENTEN",Swe=()=>"COMMUNICATIE",Ewe=()=>"ANOMALIEMONITOR",Twe=()=>"ENKELE REIS",Awe=()=>"HEEN EN TERUG",Rwe=e=>`${e.value} l-min`,wwe=()=>"NOMINAAL",Nwe=()=>"WAARSCHUWING",Iwe=()=>"KRITIEK",Owe=()=>"Geen gebeurtenissen geregistreerd voor deze missie.",zwe=e=>`T+${e.day}d`,Lwe=()=>"VLUCHTLEIDER",Uwe=e=>`FASE · ${e.phase}`,xwe=()=>"→ Lees in /science",jwe=()=>"Vertrek · lanceerenergie",Dwe=()=>"C3 is de gekwadrateerde lanceerenergie van het voertuig na het verlaten van de Aarde. Een positieve C3 betekent dat het ruimtevaartuig het zwaartekrachtveld van de Aarde verlaat; hoe hoger het getal, hoe sneller de kruising.",Bwe=()=>"Trans-X-injectie · vastleggen op de boog",Mwe=()=>"De injectie-verbranding (TLI voor de Maan, TMI voor Mars) is de grootste enkele ∆v van de reis. Daarna staat de motor uit en zweeft het voertuig langs een Kepleriaanse boog tot aan de bestemming.",Pwe=()=>"Kruising · Hohmann-transferellips",qwe=()=>"Zweven langs een Hohmann-transferbaan — de meest brandstof-efficiënte ellips die de banen van beide planeten raakt. De Zon is de enige kracht; vis-viva geeft de snelheid op elk punt. Geen brandstofverbruik, geen motor — kruisingstijd is gratis.",Vwe=()=>"Nadering · hyperbolische aankomst",Gwe=()=>"Naderen van de bestemming. V∞ is de oversnelheid op oneindige afstand — de snelheid die het ruimtevaartuig zou hebben als de zwaartekracht van de planeet er niet was. Dit bepaalt de minimale rem-∆v voor elke baanintrede.",Hwe=()=>"Aankomst · baanintrede",Fwe=()=>"De aankomst-verbranding remt het voertuig af van zijn hyperbolische V∞ tot onder de ontsnappingssnelheid van de bestemming, zodat het in een gesloten baan wordt gevangen. Mis je deze verbranding, dan vliegt het ruimtevaartuig voor altijd voorbij.",Wwe=()=>"Waarom?",Zwe=()=>"WAAROM DIT GETAL",Kwe=()=>"→ Lees volledig in /science",Xwe=e=>`Waarom dit ertoe doet: ${e.title}`,Ywe=()=>"Uitleg sluiten",Jwe=()=>"Waarom dit voorbehoud?",Qwe=()=>"Openbare vluchtgegevens verschillen per missie. GERECONSTRUEERD betekent dat we cijfers hebben samengevoegd uit secundaire bronnen (baan-papers, agentschap-perskits, peer-reviewed heranalyse). Het is onze beste eerlijke schatting, geen ruwe telemetrie.",eNe=()=>"Sommige agentschappen brachten alleen gedeeltelijke vluchtgegevens uit. BEPERKT markeert missies waar de hoofdcijfers bestaan maar belangrijke parameters (zoals snelheden midden in de kruising of ∆v per verbranding) nooit openbaar werden gemaakt.",aNe=()=>"We hebben nog geen vluchtgegevens voor deze missie onderzocht. De missie is echt en historisch gedocumenteerd, maar de gestructureerde getallen voor visualisaties zijn nog niet uit een bron afgeleid.",nNe=()=>"Waarom de declinatie van de lanceerasymptoot (DLA)?",tNe=()=>"DLA is de breedtegraad van de uitgaande snelheidsvector van het ruimtevaartuig ten opzichte van de evenaar. Het beperkt welke lanceerbases de baan kunnen bereiken: een DLA op hoge breedte vereist een lancering met hoge inclinatie en kost ∆v.",sNe=()=>"Waarom massa bij TLI?",oNe=()=>"De natte massa direct na de trans-X-injectieverbranding bepaalt elke verdere berekening: het ∆v-budget voor de kruising, structurele lasten, zelfs de intredemassa voor landers. Twee missies kunnen vergelijkbare ladingen hebben maar zeer verschillende massa's bij TLI, afhankelijk van de getrapte configuratie.",iNe=()=>"Waarom halve hoofdas?",rNe=()=>"De helft van de lange as van een elliptische baan — de belangrijkste afzonderlijke baanparameter. Hij legt de gemiddelde afstand tot de Zon vast en (via Keplers derde wet) de baanperiode. Als je maar één getal van een baan kent, wil je dit getal.",_Ne=()=>"Waarom excentriciteit?",lNe=()=>"Hoe afgeplat de ellips is. e=0 is een perfecte cirkel; e→1 is een mes-scherpe ellips. Hoge excentriciteit betekent grote schommelingen in afstand en snelheid tussen perihelium (dichtbij, snel) en afhelium (ver weg, langzaam) — de baan voelt scheef aan.",cNe=()=>"Waarom inclinatie?",dNe=()=>"De helling van de baan ten opzichte van het referentievlak (ecliptica voor heliocentrische banen, evenaar voor Aardbanen). Banen met hoge inclinatie kosten meer ∆v om te bereiken, maar openen unieke geometrieën — polaire beeldvorming, zonsynchrone belichting, noord-zuid dekking.",pNe=()=>"Waarom baanperiode?",uNe=()=>"Hoelang één volledige rondgang om de Zon (of het centrale lichaam) duurt. Verbonden met de halve hoofdas via Keplers derde wet: P² ∝ a³. Hoe verder weg, hoe langzamer; het jaar van Neptunus is 165 aardjaren.",$Ne=()=>"Waarom perihelium?",gNe=()=>"Het dichtstbijzijnde punt van de baan tot de Zon (of waar de baan ook omheen draait). Het snelste punt — vis-viva: kleine r → grote v. Voor kometen is perihelium het moment van de show; voor ruimtevaartuigen is het de goedkoopste plek voor een Oberth-verbranding.",mNe=()=>"Waarom afhelium?",hNe=()=>"Het verste punt van de baan vanaf de Zon (of het centrale lichaam). Het langzaamste punt — vis-viva: grote r → kleine v. Goede plek om de baan goedkoop bij te stellen (kleine ∆v verschuift de andere kant veel) maar slecht voor grote verbrandingen.",bNe=()=>"Waarom askanteling?",yNe=()=>"De hoek tussen de rotatieas van een lichaam en de loodlijn op zijn baan. De 23,4° van de Aarde geven ons seizoenen. De 98° van Uranus betekent dat hij op zijn zij langs zijn baan rolt. De kanteling bepaalt ook waar de zon op- en ondergaat op landingsplaatsen — cruciaal voor zonne-energie-planning.",fNe=()=>"Waarom gemiddelde snelheid?",vNe=()=>"De gemiddelde baansnelheid. Dichterbij gelegen lichamen bewegen snel (Mercurius gemiddeld 47 km/s); buitenste lichamen kruipen (Neptunus gemiddeld 5,4 km/s). Vis-viva verbindt snelheid met positie op de ellips — perihelium is snel, afhelium is langzaam.",kNe=()=>"Waarom zonnemassa?",CNe=()=>"Massa bepaalt zwaartekracht, zwaartekracht bepaalt elke baan. De Zon is 333.000× de massa van de Aarde en domineert het zonnestelsel; dat ene getal voorspelt, samen met Keplers wetten, waar elke planeet op elk moment staat.",SNe=()=>"Waarom piek-heliocentrische snelheid?",ENe=()=>"De hoogste snelheid die het ruimtevaartuig in het zonsstelsel-referentiekader bereikt tijdens de kruising — meestal direct na de trans-X-injectieverbranding of vlakbij het perihelium van de transferboog. Geeft het kinetische-energiebudget aan waarmee het voertuig werkt.",TNe=()=>"Waarom intreesnelheid?",ANe=()=>"De snelheid waarmee het voertuig de atmosfeer van de bestemming raakt, nadat de zwaartekracht het heeft versneld. Bepaalt het ontwerp van het hitteschild — elke extra km/s betekent dramatisch meer verhitting tijdens intrede, daling en landing.",RNe=()=>"Waarom periapsis?",wNe=()=>"Het dichtstbijzijnde punt van de baan tot de bestemming na intrede. Lage periapsis = dichter bij de planeet (betere beeldvorming, meer weerstand) maar meer atmosferische verhitting; hoge periapsis = bredere baan, minder verhitting, meer brandstof om er te komen.",NNe=()=>"Waarom inclinatie bij aankomst?",INe=()=>"De helling van de gevangen baan ten opzichte van de evenaar van de bestemming. Polaire banen (90°) zien dagelijks het hele oppervlak maar kosten meer ∆v bij intrede. Equatoriale (0°) zijn goedkoop maar zien slechts een band.",ONe=()=>"Waarom deze ∆v?",zNe=()=>"Het getal telt drie stukken op: de lanceerenergie nodig om aan de Aarde te ontsnappen (C3), de kruisingsverbrandingen om de transferellips vorm te geven, en de baan-intrede-verbranding bij aankomst (nul voor een flyby). Cellen in de goedkope turkooizen lobus liggen bij een Hohmann-minimum; ribbels markeren synodische gaten waar de natuurkunde je laat wachten of betalen.",LNe=()=>"Waarom deze hoogte?",UNe=()=>"Hoogtebanden (LEO ≤ 2 000 km, MEO ≤ 35 786, GEO op 35 786, HEO daarboven) wegen grondresolutie, dekking, communicatievertraging en lanceerkosten tegen elkaar af. Operatoren kiezen hoogte volgens missie — beeldvorming wil laag, GPS wil middelhoog, omroep wil geosynchroon.",xNe=()=>"Waarom deze baanperiode?",jNe=()=>"Periode en hoogte zijn samen vastgezet door Keplers derde wet. LEO-satellieten doen één rondgang per ~90 minuten, MEO per ~12 uur, GEO per 24 uur (gelijklopend met de aardrotatie). De periode bepaalt hoe vaak de satelliet over een gegeven grondpunt komt.",DNe=()=>"Waarom deze inclinatie?",BNe=()=>"Inclinatie is de helling van de baan ten opzichte van de aard-evenaar. 0° (equatoriaal) is goedkoop vanaf laag-breedte-lanceerbases; 51,6° (ISS) is de laagste inclinatie die Russische lanceringen halen zonder over bewoonde gebieden te vliegen; ~98° (zonsynchroon) houdt dezelfde belichting voor beeldvorming. Het is een beperking, geen keuze.",MNe=()=>"Waarom deze landingsplaats?",PNe=()=>"Landingsplaatsen zijn een afweging: equatoriale breedten zijn goedkoop en warm maar arm aan informatie; polaire plaatsen behouden vluchtige stoffen (waterijs in permanent beschaduwde kraters) en zijn wetenschappelijk rijk maar duur. Specifieke coördinaten richten op een geologisch kenmerk — een kraterrand, een oude meerbodem, een verse inslagplaats.",qNe=()=>"Waarom deze oppervlaktetijd?",VNe=()=>"De oppervlaktetijd wordt begrensd door energie (zonne-oplading of RTG), thermische cycli en bemanning-levensondersteuning. Apollo's maandagvenster duurde ongeveer 3 aarddagen; Mars-rovers volharden jaren op RTG; statische landers vallen meestal uit als hun batterijen onder het vriespunt zakken.",GNe=()=>"Waarom EVA-tijd?",HNe=()=>"Buitenboord-activiteit (EVA) is het meest risicovolle en lonende deel van een bemande missie. Pakverbruiksgoederen, micrometeoroïde-blootstelling en CO₂-zuiveringslimieten beperken elke EVA tot ongeveer 8 uur. De totale EVA-tijd op een missie is de echte maatstaf van hoeveel oppervlaktewetenschap is gedaan.",FNe=()=>"Waarom monsterretour?",WNe=()=>"Geretourneerde monsters kunnen geanalyseerd worden met massaspectrometers, elektronenmicroscopen, isotopendatering — instrumenten te groot of energiehongerig om mee te vliegen. Apollo bracht 382 kg terug; Chang'e 5 bracht 1,7 kg jonger achterzijde-regoliet. Elke kilogram ontsluit decennia aan vervolgonderzoek.",ZNe=()=>"Waarom modulemassa?",KNe=()=>"Massa naar LEO is de onverbiddelijke valuta van stationsbouw. Elke kilogram heeft ~9,4 km/s ∆v nodig om de baan te bereiken; dat bepaalt de keuze van de draagraket en welke modules samen kunnen vliegen. Grote modules (Zarya, Tianhe) vereisen zware draagraketten; kleine kunnen meeliften op vrachtvluchten.",XNe=()=>"Waarom modulelengte?",YNe=()=>"De modulelengte wordt beperkt door de neuskap van de raket — de aerodynamische conus die de module beschermt tijdens de lancering. De neuskap van Falcon 9 is 13,2 m hoog; die van Long March 5B is 20 m. Modules langer dan de neuskap kunnen simpelweg niet op die raket vliegen.",JNe=()=>"BAANREGIME",QNe=()=>"→ Lees in /science",eIe=()=>"HGT",aIe=()=>"INCL",nIe=()=>"PERIODE",tIe=e=>`${e.value} km`,sIe=e=>`${e.value}°`,oIe=e=>`${e.value} min`,iIe=()=>"Waarom deze hoogte?",rIe=()=>"Beide stations bevinden zich in een lage Aardbaan, ~400 km hoog. Onder ~330 km verbruikt atmosferische weerstand de baanenergie sneller dan de bezoekende vrachtschepen kunnen reboosten. Boven ~500 km begint de binnenste Van Allen-stralingsgordel zich te laten gelden, en de reikwijdte van bemande voertuigen daalt. De band 350-450 km is het optimum.",_Ie=()=>"Waarom deze inclinatie?",lIe=()=>"De inclinatie wordt bepaald door de lanceerbase, niet door voorkeur van de ontwerper. ISS op 51,6° is de laagste inclinatie die Russische Sojoez-lanceringen kunnen halen zonder verbruikte trappen op bewoond land te laten vallen. Tiangong op 41,5° is bereikbaar vanaf Wenchang in Zuid-China zonder over bewoonde gebieden te vliegen. Elke keuze ruilt lanceer-∆v voor grondbedekking-bereik.",cIe=()=>"Waarom ~92 minuten?",dIe=()=>"Keplers derde wet: op ~400 km is de periode vastgepind op ongeveer 92 minuten. Dat zijn 16 zonsopgangen en 16 zonsondergangen per bemanningsdag — het circadiaanse ritme van het lichaam wordt zwaar belast, daarom leven bemanningen op een synthetische 24-uurs missietijd ingesteld op UTC.",pIe=()=>"Waarom 16 zonsopgangen per dag?",uIe=()=>"Banen van 92 minuten × 24 uur = 15,6 ronden per dag, elk twee keer over de dag/nacht-grens. Bemanningen zien dagelijks ongeveer 16 zonsopgangen en 16 zonsondergangen. De cabine gebruikt geplande verlichting volgens UTC zodat het circadiaanse ritme niet desynchroniseert.",$Ie=()=>"MICROZWAARTEKRACHT-FRAME",gIe=()=>"ZENIT · NADIR",mIe=()=>"Omhoog (weg van de Aarde) en omlaag (naar de Aarde toe). Belangrijk voor zonnepaneel-richting + radiator-plaatsing.",hIe=()=>"VOORWAARTS · ACHTERWAARTS",bIe=()=>"Richting van de baanbeweging + zijn tegengestelde. Reboost-verbrandingen vuren prograde; deboost-verbrandingen vuren retrograde.",yIe=()=>"BAKBOORD · STUURBOORD",fIe=()=>"Links en rechts van de snelheidsvector. Truss-segmenten genaamd P1/P3/P4/P5 (bakboord) en S1/S3/S4/S5 (stuurboord) volgen deze conventie.",vIe=()=>"→ Lees in /science",kIe=()=>"→ Bemand-vluchts uithoudingsvermogen",CIe=()=>"→ EVA — hoe ruimtewandelingen werken",SIe=()=>"WETENSCHAPSLAGEN",EIe=()=>"Invloedssferen",TIe=()=>"Doorzichtige ringen die laten zien waar de zwaartekracht van elk lichaam domineert.",AIe=()=>"Hover-infokaarten",RIe=()=>"Live cijfers (snelheid, afstand, zwaartekracht) bij het zweven over een planeet.",wIe=()=>"Zwaartekrachtvectoren",NIe=()=>"Krachtpijlen vanuit elk lichaam, log-geschaald zodat alle zichtbaar zijn.",IIe=()=>"Snelheidsvectoren",OIe=()=>"Tangentpijlen die de momentane heliocentrische snelheid tonen.",zIe=()=>"Middelpuntzoekende pijlen",LIe=()=>"Naar binnen gerichte versnellingspijlen die de zwaartekracht balanceren (F = ma).",UIe=()=>"Apsiden + ware anomalie",xIe=()=>"Markers voor perihelium / afhelium + de live ν = 42°-hoek.",jIe=()=>"Voorvertoning motorloos drijven",DIe=()=>"Waar het ruimtevaartuig naartoe zou drijven als de motor nu zou uitvallen.",BIe=()=>"Familie van kegelsneden",MIe=()=>"Benoemt live de huidige boogvorm (ellips / hyperbool / etc.).",PIe=()=>"Microzwaartekracht-assen",qIe=()=>"Drie kleur-gecodeerde lichaamsassen — zenit / nadir, prograde / retrograde, bakboord / stuurboord.",VIe=()=>"Atmosferische schil",GIe=()=>"Doorzichtige schil aan de effectieve atmosferische rand van het lichaam — Kármán-lijn op de Aarde, ~120 km op Mars.",HIe=()=>"Getijdenslot-indicator",FIe=()=>"Markeert de naar-de-Aarde-gerichte halfrond van de Maan — het resultaat van synchrone rotatie.",WIe=()=>"Ozongaten",ZIe=()=>"Polaire ozonafnamezones — Antarctisch + Arctisch — die seizoensgewijs openen wanneer ClO en BrO O₃-vernietiging in de stratosfeer katalyseren.",KIe=()=>"RUIMTEVAARTUIG · LIVE",XIe=()=>"KEGELSNEDE",YIe=()=>"→ Lees in /science",JIe=()=>"Cirkel",QIe=()=>"Ellips",eOe=()=>"Parabool",aOe=()=>"Hyperbool",nOe=()=>"Effectief constante straal — snelheid en afstand veranderen nooit.",tOe=()=>"Gebonden baan. Zon in één brandpunt; snelheid piekt op perihelium, daalt op afhelium.",sOe=()=>"Mes-scherpe ontsnapping — precies genoeg snelheid om weg te gaan, nooit om terug te keren.",oOe=()=>"Ongebonden. Oversnelheid voorbij ontsnapping; het lichaam blijft eeuwig doorgaan.",iOe=()=>"Aardbaan-3D-scène",rOe=()=>"2D",_Oe=()=>"3D",lOe=()=>"HOOGTE",cOe=()=>"PERIODE",dOe=()=>"INCLINATIE",pOe=()=>"GELANCEERD",uOe=()=>"CREW",$Oe=()=>"AANTAL",gOe=e=>`${e.value} km`,mOe=e=>`${e.value} min`,hOe=e=>`${e.value}°`,bOe=()=>"Kon Aardbaan-objecten niet laden.",yOe=()=>"Maan-3D-scène",fOe=()=>"3D",vOe=()=>"2D",kOe=()=>"JAAR",COe=()=>"LANDING",SOe=()=>"BREEDTEGRAAD",EOe=()=>"LENGTEGRAAD",TOe=()=>"TIJD OP OPPERVLAK",AOe=()=>"EVA-TIJD",ROe=()=>"MONSTERS",wOe=()=>"CREW",NOe=()=>"NOG OP HET OPPERVLAK",IOe=()=>"NIEUWE CAPACITEIT",OOe=e=>`${e.value}°`,zOe=e=>`${e.value}°`,LOe=e=>`${e.value} dagen`,UOe=e=>`${e.value} u`,xOe=e=>`${e.value} kg`,jOe=()=>"Kon Maan-landingsplaatsen niet laden.",DOe=()=>"Hoofdnavigatie",BOe=()=>"Paneel sluiten",MOe=()=>"Detailpaneel",POe=()=>"AARDE",qOe=()=>"ISS Verkenner · Orrery",VOe=()=>"PROBEER 3D",GOe=()=>"LIJST",HOe=()=>"MODULES",FOe=()=>"MODULES VERBERGEN",WOe=()=>"Index sluiten",ZOe=()=>"Kon ISS-modules niet laden.",KOe=()=>"3D-modus leek traag op dit apparaat — overgeschakeld naar de lijst. Gebruik de schakelaar om opnieuw 3D te proberen.",XOe=()=>"Lage-geheugenmodus: lijstweergave eerst. Gebruik de schakelaar om 3D te proberen.",YOe=()=>"Sleep om te roteren · tik op een module",JOe